{"file_path": "/project/ktlint-ruleset-standard/src/main/kotlin/com/pinterest/ktlint/ruleset/standard/rules/SpacingAroundColonRule.kt", "old_string": "    private inline val ASTNode.removeSpacingBefore: Boolean
        get() =
            psi
                .parent
                .let { psiParent ->
                    psiParent !is KtClassOrObject &&
                        psiParent !is KtConstructor<*> && // constructor : this/super
                        psiParent !is KtTypeConstraint && // where T : S
                        psiParent?.parent !is KtTypeParameterList
                }
}", "new_string": "    /**
     * Remove unexpected spacing around colon in annotation. No spacing is allowed around the colon.
     */
    private fun removeUnexpectedSpacingAround(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val spacingBefore = node.prevSibling()?.takeIf { it.isWhiteSpace() }
        val spacingAfter = node.nextSibling()?.takeIf { it.isWhiteSpace() }
        when {
            spacingBefore != null && spacingAfter != null -> {
                emit(node.startOffset, "Unexpected spacing around \":\"", true)
                if (autoCorrect) {
                    spacingBefore.treeParent.removeChild(spacingBefore)
                    spacingAfter.treeParent.removeChild(spacingAfter)
                }
            }
            spacingBefore != null -> {
                emit(node.startOffset, "Unexpected spacing before \":\"", true)
                if (autoCorrect) {
                    spacingBefore.treeParent.removeChild(spacingBefore)
                }
            }
            spacingAfter != null -> {
                emit(node.startOffset + 1, "Unexpected spacing after \":\"", true)
                if (autoCorrect) {
                    spacingAfter.treeParent.removeChild(spacingAfter)
                }
            }
        }
    }

    private inline val ASTNode.removeSpacingBefore: Boolean
        get() =
            psi
                .parent
                .let { psiParent ->
                    psiParent !is KtClassOrObject &&
                        psiParent !is KtConstructor<*> && // constructor : this/super
                        psiParent !is KtTypeConstraint && // where T : S
                        psiParent?.parent !is KtTypeParameterList
                }
}"}

